import { useState } from 'react';
import { Link, useNavigate, useParams } from 'react-router-dom';
import { Icon } from '@/components/Icon';
import { PageHeader } from '@/components/layout/PageHeader';
import { EmptyState } from '@/components/data/EmptyState';
import { formatDateTime } from '@/lib/format';
import type { QueryStepSnapshot } from '@/api/generated/beacon-api';
import {
  useQueryDetailQuery,
  useQueryVersionDetailQuery,
  useRestoreQueryVersion,
} from './queries';

export default function QueryVersionDetailPage() {
  const { id, versionId } = useParams();
  const navigate = useNavigate();
  const queryId = id ? Number.parseInt(id, 10) : Number.NaN;
  const versionIdNum = versionId ? Number.parseInt(versionId, 10) : Number.NaN;

  const currentQuery = useQueryDetailQuery(Number.isNaN(queryId) ? undefined : queryId);
  const versionQuery = useQueryVersionDetailQuery(Number.isNaN(versionIdNum) ? undefined : versionIdNum);
  const restoreMutation = useRestoreQueryVersion(queryId);
  const [restoreConfirm, setRestoreConfirm] = useState(false);

  if (Number.isNaN(queryId) || Number.isNaN(versionIdNum)) {
    return (
      <div className="page">
        <PageHeader title="Query version detail" />
        <EmptyState icon={<Icon.Alert size={20} />} title="Invalid id in URL" />
      </div>
    );
  }

  if (versionQuery.isError) {
    return (
      <div className="page">
        <PageHeader title="Query version detail" />
        <EmptyState
          icon={<Icon.Alert size={20} />}
          title="Failed to load version"
          description={versionQuery.error instanceof Error ? versionQuery.error.message : 'Unknown error'}
        />
      </div>
    );
  }

  const version = versionQuery.data;
  const current = currentQuery.data;

  const handleRestore = async () => {
    await restoreMutation.mutateAsync(versionIdNum);
    setRestoreConfirm(false);
    navigate(`/queries/${queryId}`);
  };

  return (
    <div className="page">
      <PageHeader
        title={`Version v${version?.versionNumber ?? versionId}`}
        sub={
          <span className="muted">
            <Link to={`/queries/${queryId}/versions`}>← versions</Link>
            <span style={{ margin: '0 6px' }}>·</span>
            {version?.createdTime ? formatDateTime(version.createdTime) : '—'}
            {version?.changeSource && (
              <span style={{ marginLeft: 6 }}>· {version.changeSource}</span>
            )}
            {version?.changeReason && (
              <span style={{ marginLeft: 6 }}>· "{version.changeReason}"</span>
            )}
          </span>
        }
        actions={
          <div style={{ display: 'flex', gap: 8 }}>
            <Link className="btn" to={`/queries/${queryId}`}>
              <Icon.ArrowsLR size={14} className="btn__icon" />
              Current version
            </Link>
            {!restoreConfirm ? (
              <button
                type="button"
                className="btn btn--primary"
                onClick={() => setRestoreConfirm(true)}
                disabled={restoreMutation.isPending}
              >
                <Icon.Refresh size={14} className="btn__icon" />
                Restore this version
              </button>
            ) : (
              <>
                <button
                  type="button"
                  className="btn"
                  onClick={() => setRestoreConfirm(false)}
                >
                  Cancel
                </button>
                <button
                  type="button"
                  className="btn btn--primary"
                  onClick={handleRestore}
                  disabled={restoreMutation.isPending}
                >
                  {restoreMutation.isPending ? 'Restoring…' : 'Confirm restore'}
                </button>
              </>
            )}
          </div>
        }
      />

      {versionQuery.isLoading && (
        <div className="muted">Loading version…</div>
      )}

      {version && (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
          <div>
            <div className="card" style={{ padding: 16, marginBottom: 12 }}>
              <div style={{ fontWeight: 600, marginBottom: 8 }}>
                This version <span className="pill" style={{ marginLeft: 8 }}>v{version.versionNumber}</span>
              </div>
              <div className="muted" style={{ fontSize: 12, marginBottom: 8 }}>
                {version.name} · {(version.steps ?? []).length} step{(version.steps ?? []).length === 1 ? '' : 's'}
              </div>
              {(version.steps ?? []).map(step => (
                <StepBlock key={step.stepOrder} step={step} label="version" />
              ))}
              {version.finalQuery && (
                <div style={{ marginTop: 12 }}>
                  <div className="muted" style={{ fontSize: 12, marginBottom: 4 }}>Final query</div>
                  <pre
                    style={{
                      background: 'var(--surface-raised)',
                      border: '1px solid var(--border)',
                      borderRadius: 6,
                      padding: 10,
                      fontSize: 12,
                      overflowX: 'auto',
                      whiteSpace: 'pre-wrap',
                      margin: 0,
                    }}
                  >
                    {version.finalQuery}
                  </pre>
                </div>
              )}
            </div>
          </div>

          <div>
            <div className="card" style={{ padding: 16, marginBottom: 12 }}>
              <div style={{ fontWeight: 600, marginBottom: 8 }}>
                Current version <span className="pill pill--ok" style={{ marginLeft: 8 }}>live</span>
              </div>
              {currentQuery.isLoading && <div className="muted">Loading…</div>}
              {current && (
                <>
                  <div className="muted" style={{ fontSize: 12, marginBottom: 8 }}>
                    {current.name} · {current.steps.length} step{current.steps.length === 1 ? '' : 's'}
                  </div>
                  {current.steps.map(step => (
                    <StepBlock
                      key={step.stepOrder}
                      step={{ stepOrder: step.stepOrder, stepName: step.name, sqlValue: step.sqlValue }}
                      label="current"
                    />
                  ))}
                  {current.finalQuery && (
                    <div style={{ marginTop: 12 }}>
                      <div className="muted" style={{ fontSize: 12, marginBottom: 4 }}>Final query</div>
                      <pre
                        style={{
                          background: 'var(--surface-raised)',
                          border: '1px solid var(--border)',
                          borderRadius: 6,
                          padding: 10,
                          fontSize: 12,
                          overflowX: 'auto',
                          whiteSpace: 'pre-wrap',
                          margin: 0,
                        }}
                      >
                        {current.finalQuery}
                      </pre>
                    </div>
                  )}
                </>
              )}
            </div>
          </div>
        </div>
      )}

      {version && (version.steps ?? []).length === 0 && !currentQuery.isLoading && (
        <EmptyState
          icon={<Icon.Layers size={20} />}
          title="No steps in this version"
          description="This version snapshot has no step data recorded."
        />
      )}
    </div>
  );
}

interface StepBlockStep {
  stepOrder?: number;
  stepName?: string | null;
  sqlValue?: string | null;
}

function StepBlock({ step }: { step: StepBlockStep | QueryStepSnapshot; label?: string }) {
  const name = (step as StepBlockStep).stepName ?? (step as QueryStepSnapshot).name ?? `Step ${step.stepOrder}`;
  const sql = (step as StepBlockStep).sqlValue ?? (step as QueryStepSnapshot).sqlValue ?? '';

  return (
    <div style={{ marginBottom: 10 }}>
      <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
        <span className="muted" style={{ fontSize: 11 }}>Step {step.stepOrder}</span>
        <span style={{ fontSize: 12, fontWeight: 500 }}>{name}</span>
      </div>
      <pre
        style={{
          background: 'var(--surface-raised)',
          border: '1px solid var(--border)',
          borderRadius: 6,
          padding: 10,
          fontSize: 12,
          overflowX: 'auto',
          maxHeight: 200,
          whiteSpace: 'pre-wrap',
          margin: 0,
        }}
      >
        {sql || <span className="muted">(empty)</span>}
      </pre>
    </div>
  );
}
